require "event.BaseEvent"

IslandFrozenEvent = class("IslandFrozenEvent", BaseEvent)

function IslandFrozenEvent:onTriggered(player)
    --MsgSender.sendTopTipsToTarget(0, 5, Messages:msgIslandFrozen(player.name, island.config.id))
    local island = IslandConfig:randomIsland(IslandConfig:inWhichIsland(player:getPosition()), 0)
    if island == nil then
        return
    end
    local pos = island:getCenterPos()
    MsgSender.sendCenterTipsToTarget(player.rakssid, 5, Messages:msgIslandFrozenToOwn(island.config.id))
    GameMatch:lookingPlayer(5, island.config.id, Messages:msgIslandFrozen(GameMatch:nameAndTeamId(player), island.config.id))

    EngineWorld:addSimpleEffect("147_snow.effect", VectorUtil.newVector3(pos.x, pos.y, pos.z), 0,
            self.config.time * 1000, 0, 10)
    EngineWorld:addSimpleEffect("147_snow1.effect", VectorUtil.newVector3(pos.x, pos.y - 15, pos.z), 0,
            self.config.time * 1000, 0, 10)
    local players = PlayerManager:getPlayers()
    for _, Pplayer in pairs(players) do
        if IslandConfig:inWhichIsland(Pplayer:getPosition()) == island.config.id then
            Pplayer:setOnFrozen(self.config.time * 1000)
        end
    end
end

return IslandFrozenEvent